PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE devices (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL DEFAULT '',
      ip TEXT DEFAULT '',
      model TEXT DEFAULT '',
      type TEXT DEFAULT 'printer',
      location TEXT DEFAULT '',
      machineId TEXT DEFAULT '',
      serialNumber TEXT DEFAULT '',
      status TEXT DEFAULT 'offline',
      lastSeen TEXT DEFAULT '',
      x REAL DEFAULT 0,
      y REAL DEFAULT 0,
      blueprintId TEXT DEFAULT '',
      supplies TEXT DEFAULT '[]',
      messages TEXT DEFAULT '[]',
      inputTrays TEXT DEFAULT '[]',
      pageCount INTEGER DEFAULT 0,
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE supply_history (
      id TEXT PRIMARY KEY,
      deviceId TEXT DEFAULT '',
      supplyName TEXT DEFAULT '',
      level INTEGER DEFAULT 0,
      maxCapacity INTEGER DEFAULT 0,
      percentage REAL DEFAULT 0,
      timestamp TEXT DEFAULT ''
    );
CREATE TABLE snmp_traps (
      id TEXT PRIMARY KEY,
      sourceIp TEXT DEFAULT '',
      trapData TEXT DEFAULT '',
      parsedMessage TEXT DEFAULT '',
      severity TEXT DEFAULT '',
      receivedAt TEXT DEFAULT '',
      processed INTEGER DEFAULT 0,
      resolvedAt TEXT DEFAULT '',
      resolvedBy TEXT DEFAULT '',
      assignedTo TEXT DEFAULT '',
      assignedAt TEXT DEFAULT ''
    );
CREATE TABLE technicians (
      id TEXT PRIMARY KEY,
      name TEXT DEFAULT '',
      email TEXT DEFAULT '',
      phone TEXT DEFAULT '',
      active INTEGER DEFAULT 1,
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE email_config (
      key TEXT PRIMARY KEY,
      value TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE email_history (
      id TEXT PRIMARY KEY,
      deviceId TEXT DEFAULT '',
      recipient TEXT DEFAULT '',
      cc TEXT DEFAULT '',
      subject TEXT DEFAULT '',
      body TEXT DEFAULT '',
      htmlBody TEXT DEFAULT '',
      sentAt TEXT DEFAULT '',
      status TEXT DEFAULT '',
      errorMessage TEXT DEFAULT ''
    );
CREATE TABLE settings (
      key TEXT PRIMARY KEY,
      value TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE ms_graph_config (
      key TEXT PRIMARY KEY,
      value TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE blueprints (
      id TEXT PRIMARY KEY,
      name TEXT DEFAULT '',
      imageData TEXT DEFAULT '',
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE teachers (
      id TEXT PRIMARY KEY,
      empId TEXT DEFAULT '',
      name TEXT DEFAULT '',
      email TEXT DEFAULT '',
      roomNumber TEXT DEFAULT '',
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE device_types (
      id TEXT PRIMARY KEY,
      name TEXT DEFAULT '',
      icon TEXT DEFAULT '',
      color TEXT DEFAULT '',
      pageTitle TEXT DEFAULT '',
      description TEXT DEFAULT '',
      blueprintId TEXT DEFAULT '',
      active INTEGER DEFAULT 1,
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE issue_buttons (
      id TEXT PRIMARY KEY,
      deviceTypeId TEXT DEFAULT '',
      label TEXT DEFAULT '',
      icon TEXT DEFAULT '',
      color TEXT DEFAULT '',
      sortOrder INTEGER DEFAULT 0,
      active INTEGER DEFAULT 1,
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    , imageDataUrl TEXT DEFAULT '');
CREATE TABLE service_requests (
      id TEXT PRIMARY KEY,
      deviceId TEXT DEFAULT '',
      deviceName TEXT DEFAULT '',
      deviceType TEXT DEFAULT '',
      location TEXT DEFAULT '',
      blueprintId TEXT DEFAULT '',
      issueType TEXT DEFAULT '',
      issueLabel TEXT DEFAULT '',
      employeeId TEXT DEFAULT '',
      employeeName TEXT DEFAULT '',
      employeeEmail TEXT DEFAULT '',
      technicianId TEXT DEFAULT '',
      technicianName TEXT DEFAULT '',
      status TEXT DEFAULT 'pending',
      notes TEXT DEFAULT '',
      submittedAt TEXT DEFAULT '',
      assignedAt TEXT DEFAULT '',
      completedAt TEXT DEFAULT '',
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE qr_codes (
      id TEXT PRIMARY KEY,
      deviceId TEXT DEFAULT '',
      qrData TEXT DEFAULT '',
      generatedAt TEXT DEFAULT '',
      printedAt TEXT DEFAULT '',
      active INTEGER DEFAULT 1
    );
CREATE TABLE email_templates (
      id TEXT PRIMARY KEY,
      name TEXT DEFAULT '',
      type TEXT DEFAULT '',
      subject TEXT DEFAULT '',
      htmlBody TEXT DEFAULT '',
      active INTEGER DEFAULT 1,
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE incidents (
      id TEXT PRIMARY KEY,
      employeeId TEXT DEFAULT '',
      employeeName TEXT DEFAULT '',
      employeeEmail TEXT DEFAULT '',
      roomNumber TEXT DEFAULT '',
      shortDescription TEXT DEFAULT '',
      description TEXT DEFAULT '',
      category TEXT DEFAULT '',
      subcategory TEXT DEFAULT '',
      channel TEXT DEFAULT '',
      impact TEXT DEFAULT '',
      userType TEXT DEFAULT '',
      snowIncidentNumber TEXT DEFAULT '',
      snowUrl TEXT DEFAULT '',
      emailStatus TEXT DEFAULT 'not-sent',
      emailSentAt TEXT DEFAULT '',
      status TEXT DEFAULT 'open',
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE email_queue (
      id TEXT PRIMARY KEY,
      incidentId TEXT DEFAULT '',
      "to" TEXT DEFAULT '',
      subject TEXT DEFAULT '',
      body TEXT DEFAULT '',
      status TEXT DEFAULT 'pending',
      scheduledAt TEXT DEFAULT '',
      sentAt TEXT DEFAULT '',
      createdAt TEXT DEFAULT '',
      error TEXT DEFAULT ''
    );
CREATE TABLE ai_training (
      id TEXT PRIMARY KEY,
      rawDescription TEXT DEFAULT '',
      improvedDescription TEXT DEFAULT '',
      category TEXT DEFAULT '',
      subcategory TEXT DEFAULT '',
      channel TEXT DEFAULT '',
      impact TEXT DEFAULT '',
      serviceOffering TEXT DEFAULT '',
      keywords TEXT DEFAULT '',
      aiAccepted INTEGER DEFAULT 0,
      confidence REAL DEFAULT 0,
      source TEXT DEFAULT '',
      incidentId TEXT DEFAULT '',
      createdAt TEXT DEFAULT ''
    );
CREATE TABLE computer_repairs (
      id TEXT PRIMARY KEY,
      employeeId TEXT DEFAULT '',
      employeeName TEXT DEFAULT '',
      employeeEmail TEXT DEFAULT '',
      roomNumber TEXT DEFAULT '',
      serialNumber TEXT DEFAULT '',
      computerModel TEXT DEFAULT '',
      manufacturer TEXT DEFAULT '',
      warrantyDate TEXT DEFAULT '',
      warrantyStatus TEXT DEFAULT 'unknown',
      assetTag TEXT DEFAULT '',
      shortDescription TEXT DEFAULT '',
      description TEXT DEFAULT '',
      category TEXT DEFAULT '',
      subcategory TEXT DEFAULT '',
      channel TEXT DEFAULT '',
      impact TEXT DEFAULT '',
      userType TEXT DEFAULT '',
      snowIncidentNumber TEXT DEFAULT '',
      snowUrl TEXT DEFAULT '',
      repairStatus TEXT DEFAULT 'pending',
      emailStatus TEXT DEFAULT 'not-sent',
      emailSentAt TEXT DEFAULT '',
      photoDataUrl TEXT DEFAULT '',
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT '',
      isQuickTicket INTEGER DEFAULT 0
    );
CREATE TABLE cr_training (
      id TEXT PRIMARY KEY,
      rawDescription TEXT DEFAULT '',
      improvedDescription TEXT DEFAULT '',
      category TEXT DEFAULT '',
      subcategory TEXT DEFAULT '',
      impact TEXT DEFAULT '',
      aiAccepted INTEGER DEFAULT 0,
      confidence REAL DEFAULT 0,
      source TEXT DEFAULT '',
      repairId TEXT DEFAULT '',
      isQuickTicket INTEGER DEFAULT 0,
      createdAt TEXT DEFAULT ''
    );
CREATE TABLE repair_templates (
      id TEXT PRIMARY KEY,
      name TEXT DEFAULT '',
      icon TEXT DEFAULT '',
      shortDescription TEXT DEFAULT '',
      description TEXT DEFAULT '',
      channel TEXT DEFAULT '',
      category TEXT DEFAULT '',
      subcategory TEXT DEFAULT '',
      serviceOffering TEXT DEFAULT '',
      manufacturer TEXT DEFAULT '',
      model TEXT DEFAULT '',
      assetLocation TEXT DEFAULT '',
      impact TEXT DEFAULT '',
      userType TEXT DEFAULT '',
      requiresSerial INTEGER DEFAULT 0,
      requiresPhoto INTEGER DEFAULT 0,
      sortOrder INTEGER DEFAULT 0,
      active INTEGER DEFAULT 1,
      createdAt TEXT DEFAULT '',
      updatedAt TEXT DEFAULT ''
    );
CREATE TABLE request_page_branding (
      id INTEGER PRIMARY KEY DEFAULT 1,
      logoDataUrl TEXT DEFAULT '',
      headerTitle TEXT DEFAULT 'SHARKQUICK',
      headerSubtitle TEXT DEFAULT 'SERVICE REQUEST PORTAL',
      backgroundColor TEXT DEFAULT '#7BA3C9',
      headerBackgroundColor TEXT DEFAULT '#6B8FB8',
      cardBackgroundColor TEXT DEFAULT '#F5F0E6',
      deviceInfoBackgroundColor TEXT DEFAULT '#6B8FB8',
      buttonColor TEXT DEFAULT '#5CB85C',
      titleColor TEXT DEFAULT '#3D5A73',
      subtitleColor TEXT DEFAULT '#C9524A',
      fontFamily TEXT DEFAULT 'Inter',
      buttonBorderRadius TEXT DEFAULT '20',
      buttonTextColor TEXT DEFAULT '#FFFFFF'
    , headerLayout TEXT DEFAULT 'horizontal', cardGradientStart TEXT DEFAULT '#6B8FB8', cardGradientEnd TEXT DEFAULT '#C8D8E8', buttonBackground TEXT DEFAULT '#F2F2F2', employeeCardBackground TEXT DEFAULT '#FFFFFF', welcomeText TEXT DEFAULT 'Welcome, {name}!', showDeviceInfo TEXT DEFAULT 'minimal', showRememberUsername TEXT DEFAULT 'true', headerStripeColor TEXT DEFAULT '#5B8DB8', logoSize TEXT DEFAULT '140');
CREATE INDEX idx_devices_ip ON devices(ip);
CREATE INDEX idx_devices_type ON devices(type);
CREATE INDEX idx_supply_deviceId ON supply_history(deviceId);
CREATE INDEX idx_traps_sourceIp ON snmp_traps(sourceIp);
CREATE INDEX idx_traps_processed ON snmp_traps(processed);
CREATE INDEX idx_teachers_empId ON teachers(empId);
CREATE INDEX idx_sr_status ON service_requests(status);
COMMIT;
